function parseBureauDate(dateStr: string | undefined): Date | undefined {
  if (!dateStr || dateStr === '-' || dateStr === '') return undefined;
  const parsed = new Date(dateStr);
  return isNaN(parsed.getTime()) ? undefined : parsed;
}

