  contactsTable: 'table.rpt_content_table.rpt_content_header.rpt_content_contacts',

  // Bureau header classes
  headerTransunion: '.headerTUC',
  headerExperian: '.headerEXP',
  headerEquifax: '.headerEQF',

  // Cell classes
  labelCell: 'td.label',
  infoCell: 'td.info',

  // Account headers
  accountHeader: 'div.sub_header.ng-binding.ng-scope',
  accountHeaderAlt: 'div.sub_header.ng-binding',

  // Content wrappers
  contentWrapper: '.rpt_content_wrapper',
  fullReportHeader: '.rpt_fullReport_header',

  // Two-year payment history
  paymentHistoryTable: 'table.rpt_content_table.addr_hsrty',
  paymentHistoryHeader: 'div.hstry-header.hstry-header-2yr',
};

// Derogatory detection patterns (from PHP)
const DEROGATORY_PATTERNS = [
  'collection/chargeoff',
  'chargeoff',
  'charge off',
  'late 30',
  'late 60',
  'late 90',
  'late 120',
  'late 150',
  'late 180',
];

// Bureau column indices (0-based, column 0 is label)
const BUREAU_COLUMNS = {
  transunion: 1,
  experian: 2,
  equifax: 3,
};

// Payment history CSS class patterns
const PAYMENT_HISTORY_CLASSES = {
  late30: 'hstry-30',
  late60: 'hstry-60',
  late90: 'hstry-90',
  late120: 'hstry-120',
  late150: 'hstry-150',
  late180: 'hstry-180',
  chargeOff: 'hstry-other',
  collection: 'hstry-co',
  ok: 'hstry-ok',
};

const IDENTITYIQ_PATTERNS = {
  dofd: /(?:date\s*of\s*first\s*delinquency|first\s*delinquency|dofd)\s*:?[\s\n]*(\d{1,2}[\/\-]\d{1,2}[\/\-]\d{2,4})/i,
  removalDate: /(?:on\s*record\s*until|will\s*be\s*removed\s*by|scheduled\s*to\s*continue\s*until)\s*:?[\s\n]*(\d{1,2}[\/\-]\d{4}|\d{1,2}[\/\-]\d{1,2}[\/\-]\d{2,4})/i,
